def _validate_payment_inputs(card_number: str, amount: float, currency: str) -> None:
    """Raise ValueError for any invalid payment parameters."""
    if not card_number or len(card_number) < 16:
        raise ValueError('Invalid card number')
    if amount <= 0:
        raise ValueError('Amount must be positive')
    if currency not in SUPPORTED_CURRENCIES:
        raise ValueError(f'Unsupported currency: {currency}')


def _get_pending_order(order_id: int):
    """Return the order or raise if it doesn't exist / isn't pending."""
    order = db.query('SELECT * FROM orders WHERE id = ?', order_id)
    if not order:
        raise ValueError(f'Order {order_id} not found')
    if order.status != 'pending':
        raise ValueError(f'Order already {order.status}')
    return order


def _charge_card(card_number: str, amount: float, currency: str,
                 order_id: int, user_id: int):
    """Submit the Stripe charge and return the response, or raise PaymentError."""
    response = stripe.charge.create(
        amount=int(amount * 100),
        currency=currency.lower(),
        source=card_number,
        metadata={'order_id': order_id, 'user_id': user_id},
    )
    if response.status != 'succeeded':
        raise PaymentError(f'Charge failed: {response.failure_message}')
    return response


def _record_payment(order_id: int, user_id: int, amount: float,
                    currency: str, charge_id: str) -> None:
    """Persist the successful payment and fire notifications."""
    db.execute(
        'UPDATE orders SET status=?, stripe_charge_id=? WHERE id=?',
        'paid', charge_id, order_id,
    )
    db.execute(
        'INSERT INTO transactions VALUES (?, ?, ?, ?, NOW())',
        order_id, user_id, amount, currency,
    )
    send_email(user_id, 'payment_success', order_id=order_id, amount=amount)
    log_audit(user_id, 'payment', order_id=order_id, amount=amount, currency=currency)


def process_payment(order_id: int, card_number: str, amount: float,
                    currency: str, user_id: int) -> dict:
    """Validate, charge and record a payment for the given order."""
    _validate_payment_inputs(card_number, amount, currency)
    _get_pending_order(order_id)
    try:
        response = _charge_card(card_number, amount, currency, order_id, user_id)
    except PaymentError:
        db.execute('UPDATE orders SET status=? WHERE id=?', 'failed', order_id)
        send_email(user_id, 'payment_failed', order_id=order_id)
        raise
    _record_payment(order_id, user_id, amount, currency, response.id)
    return {'status': 'ok', 'charge_id': response.id}"
